{
  "sentences": [
    {
      "text": "我每天早上七點起床。",
      "pinyin": "Wǒ měitiān zǎoshang qī diǎn qǐchuáng.",
      "pinyin_numeric": "wo3 mei3tian1 zao3shang4 qi1 dian3 qi3chuang2",
      "translation_en": "I get up at seven every morning.",
      "translation_ko": "저는 매일 아침 7시에 일어납니다."
    },
    {
      "text": "他中午十二點吃午餐。",
      "pinyin": "Tā zhōngwǔ shí'èr diǎn chī wǔcān.",
      "pinyin_numeric": "ta1 zhong1wu3 shi2'er4 dian3 chi1 wu3can1",
      "translation_en": "He eats lunch at twelve noon.",
      "translation_ko": "그는 정오 12시에 점심을 먹습니다."
    },
    {
      "text": "我們晚上八點看電視。",
      "pinyin": "Wǒmen wǎnshang bā diǎn kàn diànshì.",
      "pinyin_numeric": "wo3men wan3shang4 ba1 dian3 kan4 dian4shi4",
      "translation_en": "We watch TV at eight in the evening.",
      "translation_ko": "우리는 저녁 8시에 텔레비전을 봅니다."
    },
    {
      "text": "她下午三點上班。",
      "pinyin": "Tā xiàwǔ sān diǎn shàngbān.",
      "pinyin_numeric": "ta1 xia4wu3 san1 dian3 shang4ban1",
      "translation_en": "She goes to work at three in the afternoon.",
      "translation_ko": "그녀는 오후 3시에 출근합니다."
    },
    {
      "text": "我哥哥晚上十一點睡覺。",
      "pinyin": "Wǒ gēge wǎnshang shíyī diǎn shuìjiào.",
      "pinyin_numeric": "wo3 ge1ge wan3shang4 shi2yi1 dian3 shui4jiao4",
      "translation_en": "My older brother goes to sleep at eleven at night.",
      "translation_ko": "제 형은 밤 11시에 잠을 잡니다."
    },
    {
      "text": "你明天早上幾點上課？",
      "pinyin": "Nǐ míngtiān zǎoshang jǐ diǎn shàngkè?",
      "pinyin_numeric": "ni3 ming2tian1 zao3shang4 ji3 dian3 shang4ke4",
      "translation_en": "What time do you have class tomorrow morning?",
      "translation_ko": "당신은 내일 아침 몇 시에 수업을 듣나요?"
    },
    {
      "text": "她每天下午五點下班。",
      "pinyin": "Tā měitiān xiàwǔ wǔ diǎn xiàbān.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 wu3 dian3 xia4ban1",
      "translation_en": "She gets off work at five every afternoon.",
      "translation_ko": "그녀는 매일 오후 5시에 퇴근합니다."
    },
    {
      "text": "我們星期六晚上七點約在餐廳。",
      "pinyin": "Wǒmen xīngqīliù wǎnshang qī diǎn yuē zài cāntīng.",
      "pinyin_numeric": "wo3men xing1qi1liu4 wan3shang4 qi1 dian3 yue1 zai4 can1ting1",
      "translation_en": "We have an appointment at the restaurant at seven on Saturday evening.",
      "translation_ko": "우리는 토요일 저녁 7시에 식당에서 약속이 있습니다."
    },
    {
      "text": "他以前早上六點起床。",
      "pinyin": "Tā yǐqián zǎoshang liù diǎn qǐchuáng.",
      "pinyin_numeric": "ta1 yi3qian2 zao3shang4 liu4 dian3 qi3chuang2",
      "translation_en": "He used to get up at six in the morning.",
      "translation_ko": "그는 예전에 아침 6시에 일어났습니다."
    },
    {
      "text": "我以後晚上十點睡覺。",
      "pinyin": "Wǒ yǐhòu wǎnshang shí diǎn shuìjiào.",
      "pinyin_numeric": "wo3 yi3hou4 wan3shang4 shi2 dian3 shui4jiao4",
      "translation_en": "From now on, I will go to sleep at ten at night.",
      "translation_ko": "저는 앞으로 밤 10시에 잠을 잘 것입니다."
    }
  ]
}
